1. namespace Textualizer.Localisation;
2. 
3. /// <summary>
4. /// Defines the contract for formatting date/time humanization output
5. /// in a locale-specific manner.
6. /// </summary>
7. public interface IFormatter
8. {
9.     /// <summary>Formats a "just now" reference.</summary>
10.     string DateHumanize_Now();
11. 
12.     /// <summary>Formats a "never" reference.</summary>
13.     string DateHumanize_Never();
14. 
15.     /// <summary>Formats a time unit reference (e.g., "2 hours ago").</summary>
16.     string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false);
17. }
18. 
19. /// <summary>
20. /// Defines the contract for ordinalizing numbers in a locale-specific manner.
21. /// </summary>
22. public interface IOrdinalizer
23. {
24.     /// <summary>
25.     /// Converts a number to its ordinal string representation (e.g., 1 → "1st").
26.     /// </summary>
27.     string Convert(int number, string numberString);
28. }
29. 
30. /// <summary>
31. /// Defines the contract for providing date-to-ordinal-words conversion.
32. /// </summary>
33. public interface IDateToOrdinalWordsConverter
34. {
35.     /// <summary>Converts a date to its ordinal words representation.</summary>
36.     string Convert(DateTime date);
37. }
38. 
39. // --- Unsealed classes (the anti-pattern) ---
40. // In Humanizer, ~185 of 186 non-abstract, non-static classes are unsealed.
41. // JIT cannot devirtualize virtual/interface calls or optimize type checks
42. // without the sealed keyword.
43. 
44. /// <summary>
45. /// Default implementation of <see cref="IFormatter"/> providing English date/time formatting.
46. /// </summary>
47. public sealed class DefaultFormatter : IFormatter
48. {
49.     /// <inheritdoc />
50.     public string DateHumanize_Now() => "now";
51. 
52.     /// <inheritdoc />
53.     public string DateHumanize_Never() => "never";
54. 
55.     /// <inheritdoc />
56.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
57.     {
58.         var unit = GetUnitName(timeUnit, count != 1);
59.         return toWords ? $"{NumberToWords(count)} {unit}" : $"{count} {unit}";
60.     }
61. 
62.     private static string GetUnitName(TimeUnit timeUnit, bool plural) =>
63.         (timeUnit, plural) switch
64.         {
65.             (TimeUnit.Year, false) => "year",
66.             (TimeUnit.Year, true) => "years",
67.             (TimeUnit.Month, false) => "month",
68.             (TimeUnit.Month, true) => "months",
69.             (TimeUnit.Day, false) => "day",
70.             (TimeUnit.Day, true) => "days",
71.             (TimeUnit.Hour, false) => "hour",
72.             (TimeUnit.Hour, true) => "hours",
73.             (TimeUnit.Minute, false) => "minute",
74.             (TimeUnit.Minute, true) => "minutes",
75.             (TimeUnit.Second, false) => "second",
76.             (TimeUnit.Second, true) => "seconds",
77.             _ => plural ? timeUnit.ToString().ToLowerInvariant() + "s"
78.                         : timeUnit.ToString().ToLowerInvariant()
79.         };
80. 
81.     private static string NumberToWords(int number) =>
82.         number switch
83.         {
84.             1 => "one",
85.             2 => "two",
86.             3 => "three",
87.             _ => number.ToString()
88.         };
89. }
90. 
91. /// <summary>
92. /// German-specific formatter providing localized date/time humanization.
93. /// </summary>
94. public sealed class GermanFormatter : IFormatter
95. {
96.     /// <inheritdoc />
97.     public string DateHumanize_Now() => "jetzt";
98. 
99.     /// <inheritdoc />
100.     public string DateHumanize_Never() => "nie";
101. 
102.     /// <inheritdoc />
103.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
104.     {
105.         var unit = GetGermanUnit(timeUnit, count);
106.         return $"{count} {unit}";
107.     }
108. 
109.     private static string GetGermanUnit(TimeUnit timeUnit, int count) =>
110.         (timeUnit, count) switch
111.         {
112.             (TimeUnit.Year, 1) => "Jahr",
113.             (TimeUnit.Year, _) => "Jahre",
114.             (TimeUnit.Month, 1) => "Monat",
115.             (TimeUnit.Month, _) => "Monate",
116.             (TimeUnit.Day, 1) => "Tag",
117.             (TimeUnit.Day, _) => "Tage",
118.             (TimeUnit.Hour, 1) => "Stunde",
119.             (TimeUnit.Hour, _) => "Stunden",
120.             (TimeUnit.Minute, 1) => "Minute",
121.             (TimeUnit.Minute, _) => "Minuten",
122.             (TimeUnit.Second, 1) => "Sekunde",
123.             (TimeUnit.Second, _) => "Sekunden",
124.             _ => timeUnit.ToString()
125.         };
126. }
