151.             (TimeUnit.Month, _) => "mois",
152.             (TimeUnit.Day, 1) => "jour",
153.             (TimeUnit.Day, _) => "jours",
154.             (TimeUnit.Hour, 1) => "heure",
155.             (TimeUnit.Hour, _) => "heures",
156.             (TimeUnit.Minute, 1) => "minute",
157.             (TimeUnit.Minute, _) => "minutes",
158.             (TimeUnit.Second, 1) => "seconde",
159.             (TimeUnit.Second, _) => "secondes",
160.             _ => timeUnit.ToString()
161.         };
162. }
